Bash(cd C:/xampp/htdocs/resume && php -r '
require_once "src/Services/PdfCompiler.php";
$compiler = new PdfCompiler\(\);
$tex = file_get_contents\("template.tex"\);
try {
    $pdfPath = $compiler->compile\($tex\);
    echo "SUCCESS: " . $pdfPath . PHP_EOL;
    echo "Size: " . filesize\($pdfPath\) . " bytes" . PHP_EOL;
    $compiler->cleanup\(dirname\($pdfPath\)\);
    echo "Cleaned up." . PHP_EOL;
} catch \(Exception $e\) {
    echo "ERROR: " . $e->getMessage\(\) . PHP_EOL;
}
')

